UPDATE J09C_temp
SET ENTSCHEIDUNG = 'KSA'
WHERE HAUS IN (
    SELECT HAUS FROM (
        SELECT HAUS, COUNT(DISTINCT EQUNR) AS eq_count
        FROM J09C_temp
        GROUP BY HAUS
    ) sub
    WHERE eq_count < 3
);

UPDATE J09C_temp
SET ENTSCHEIDUNG = COALESCE(ENTSCHEIDUNG, 'EVU')
WHERE HAUS IN (
    SELECT HAUS FROM (
        SELECT HAUS, COUNT(DISTINCT EQUNR) AS eq_count
        FROM J09C_temp
        GROUP BY HAUS
    ) sub
    WHERE eq_count >= 3
);

UPDATE J09C_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 = 0;

UPDATE J09C_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 BETWEEN 500 AND 599;

UPDATE J09C_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 BETWEEN 900 AND 999;

UPDATE J09C_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE CITY1 IN ('Wiblingwerde','Breckerfeld') OR CITY2 IN ('Wiblingwerde','Breckerfeld');

